#include <stdio.h>
#include <stdbool.h>

bool isOddDigitImmune(long long num) {
    bool hasEvenDigit = false;
    long long temp = num;
    while (temp > 0) {
        long long digit = temp % 10;
        if (digit % 2 == 0) {
            hasEvenDigit = true;
            break;
        }
        if (digit != 0 && num % digit == 0) {
            return false;
        }
        temp /= 10;
    }
    return !hasEvenDigit;
}

int main() {
    int Q;
    scanf("%d", &Q);
    while (Q-- > 0) {
        long long A, B, K;
        scanf("%lld %lld %lld", &A, &B, &K);
        long long count = 0;
        for (long long i = A; i <= B; i++) {
            if (isOddDigitImmune(i)) {
                count++;
                if (count == K) {
                    printf("%lld\n", i);
                    break;
                }
            }
        }
        if (count < K) {
            printf("-1\n");
        }
    }
    return 0;
}

